import{_ as o,c as e,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Google Cloud: Квота | opencode-mystatus","description":"Научитесь запросу квоты Google Cloud. Просматривайте оставшуюся квоту и время сброса моделей G3 Pro、G3 Image、G3 Flash и Claude, управляйте несколькими учётными записями Antigravity.","frontmatter":{"title":"Google Cloud: Квота | opencode-mystatus","sidebarTitle":"Google Cloud","subtitle":"Google Cloud: Квота","description":"Научитесь запросу квоты Google Cloud. Просматривайте оставшуюся квоту и время сброса моделей G3 Pro、G3 Image、G3 Flash и Claude, управляйте несколькими учётными записями Antigravity.","tags":["Google Cloud","Antigravity","Запрос квоты"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"ru/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"ru/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),s={name:"ru/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function i(n,a,d,r,p,c){return t(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="запрос-квоты-google-cloud-g3-pro-image-flash-и-claude" tabindex="-1">Запрос квоты Google Cloud: G3 Pro/Image/Flash и Claude <a class="header-anchor" href="#запрос-квоты-google-cloud-g3-pro-image-flash-и-claude" aria-label="Permalink to &quot;Запрос квоты Google Cloud: G3 Pro/Image/Flash и Claude&quot;">​</a></h1><h2 id="что-вы-научитесь-делать" tabindex="-1">Что вы научитесь делать <a class="header-anchor" href="#что-вы-научитесь-делать" aria-label="Permalink to &quot;Что вы научитесь делать&quot;">​</a></h2><ul><li>Просмотреть квоту 4 моделей учётной записи Google Cloud Antigravity</li><li>Поймите время сброса и оставшийся процент каждой модели</li><li>Управлять использованием квоты нескольких учётных записей Google Cloud</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Google Cloud Antigravity предоставляет несколько моделей (G3 Pro、G3 Image、G3 Flash、Claude), каждая модель имеет независимую квоту и время сброса. Вам нужно:</p><ul><li>По отдельности входить в консоль Google Cloud для просмотра статуса каждой модели</li><li>Вручную рассчитывать оставшуюся квоту и время сброса</li><li>Ещё больший хаос при управлении несколькими учётными записями</li></ul><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><p>Когда вы:</p><ul><li>Хотите быстро понять оставшуюся квоту всех моделей Google Cloud</li><li>Нужно планировать распределение использования между разными моделями</li><li>Несколько учётных записей Google Cloud требуют унифицированного управления</li></ul><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Предварительная проверка</p><ol><li><strong>Установлен плагин mystatus</strong>: см. <a href="/docs/opencodedocs/ru/vbgate/opencode-mystatus/start/quick-start/">Быстрый старт</a></li><li><strong>Настроена аутентификация Google Cloud</strong>: нужно сначала установить плагин <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> для завершения аутентификации OAuth</li><li><strong>Существует файл аутентификации</strong>: <code>~/.config/opencode/antigravity-accounts.json</code> включает хотя бы одну учётную запись</li></ol></div><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Google Cloud Antigravity аутентифицируется через механизм OAuth, каждая учётная запись имеет независимый Refresh Token. Плагин mystatus:</p><ol><li>Читает <code>antigravity-accounts.json</code> для получения всех настроенных учётных записей</li><li>Использует Refresh Token для обновления Access Token</li><li>Вызывает API Google Cloud для получения квоты всех моделей</li><li>Отображает квоту и время сброса 4 моделей по группам учётных записей</li></ol><h2 id="поддерживаемые-модели-google-cloud" tabindex="-1">Поддерживаемые модели Google Cloud <a class="header-anchor" href="#поддерживаемые-модели-google-cloud" aria-label="Permalink to &quot;Поддерживаемые модели Google Cloud&quot;">​</a></h2><p>mystatus отображает квоту следующих 4 моделей:</p><table tabindex="0"><thead><tr><th>Отображаемое имя</th><th>Ключ модели (основной/альтернативный)</th><th>Описание</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro высокопроизводительная версия</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro генерация изображений</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash быстрая версия</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5 модель</td></tr></tbody></table><p><strong>Механизм основного и альтернативного ключей</strong>:</p><ul><li>В ответе API могут быть возвращены данные только основного ключа или только альтернативного ключа</li><li>mystatus автоматически попробует получить квоту любого ключа</li><li>Например: если у <code>gemini-3-pro-high</code> нет данных, попробует <code>gemini-3-pro-low</code></li></ul><h2 id="следуите-за-мнои" tabindex="-1">Следуйте за мной <a class="header-anchor" href="#следуите-за-мнои" aria-label="Permalink to &quot;Следуйте за мной&quot;">​</a></h2><h3 id="шаг-1-выполните-команду-запроса" tabindex="-1">Шаг 1: Выполните команду запроса <a class="header-anchor" href="#шаг-1-выполните-команду-запроса" aria-label="Permalink to &quot;Шаг 1: Выполните команду запроса&quot;">​</a></h3><p><strong>Почему</strong> Быстро получить информацию о квоте всех учётных записей Google Cloud</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong></p><p>Включает информацию о квоте всех настроенных платформ, часть Google Cloud отобразит следующее содержание:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="шаг-2-понимание-формата-вывода" tabindex="-1">Шаг 2: Понимание формата вывода <a class="header-anchor" href="#шаг-2-понимание-формата-вывода" aria-label="Permalink to &quot;Шаг 2: Понимание формата вывода&quot;">​</a></h3><p><strong>Почему</strong> Быстро найти ключевую информацию: оставшуюся квоту и время сброса</p><p>Каждая строка формата:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Имя модели] [Время сброса] [Индикатор прогресса] [Оставшийся процент]</span></span></code></pre></div><p><strong>Описание полей</strong>:</p><ul><li><strong>Имя модели</strong>: G3 Pro、G3 Image、G3 Flash、Claude</li><li><strong>Время сброса</strong>: оставшееся время до следующей квоты (например, <code>4h 59m</code>、<code>2d 9h</code>)</li><li><strong>Индикатор прогресса</strong>: визуально отображает оставшийся процент</li><li><strong>Оставшийся процент</strong>: числовое значение 0-100</li></ul><p><strong>Что вы должны видеть</strong> Каждая модель на отдельной строке, чётко отображает квоту и время сброса</p><h3 id="шаг-3-просмотр-ситуации-с-несколькими-учетными-записями" tabindex="-1">Шаг 3: Просмотр ситуации с несколькими учётными записями <a class="header-anchor" href="#шаг-3-просмотр-ситуации-с-несколькими-учетными-записями" aria-label="Permalink to &quot;Шаг 3: Просмотр ситуации с несколькими учётными записями&quot;">​</a></h3><p><strong>Почему</strong> Если у вас несколько учётных записей Google Cloud, они будут отображены по отдельности</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ████████████░░░░░░░░ 75%</span></span></code></pre></div><p><strong>Что вы должны видеть</strong> Каждая учётная запись отдельный блок, включающий квоту 4 моделей этой учётной записи</p><h3 id="шаг-4-проверка-предупреждения-о-квоте" tabindex="-1">Шаг 4: Проверка предупреждения о квоте <a class="header-anchor" href="#шаг-4-проверка-предупреждения-о-квоте" aria-label="Permalink to &quot;Шаг 4: Проверка предупреждения о квоте&quot;">​</a></h3><p><strong>Почему</strong> Избежать прерывания службы из-за превышения лимита</p><p>Если использование любой модели превышает 80%, отобразится предупреждение:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     1h 30m     ████░░░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span>G3 Image   1h 30m     ████░░░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ Использование достигло или превысило 80%</span></span></code></pre></div><p><strong>Что вы должны видеть</strong> Предупреждение отобразится ниже списка моделей соответствующей учётной записи</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><p>После завершения следующей проверки убедитесь, что вы всё сделали правильно:</p><ul><li>[ ] После выполнения <code>/mystatus</code> видите информацию о квоте Google Cloud</li><li>[ ] Можете понимать имена 4 моделей и время сброса</li><li>[ ] Можете распознать индикатор прогресса и оставшийся процент</li><li>[ ] Если несколько учётных записей, видите квоту всех учётных записей</li></ul><h2 id="предупреждения-о-ловушках" tabindex="-1">Предупреждения о ловушках <a class="header-anchor" href="#предупреждения-о-ловушках" aria-label="Permalink to &quot;Предупреждения о ловушках&quot;">​</a></h2><h3 id="проблема-1-не-видите-квоту-google-cloud" tabindex="-1">Проблема 1: Не видите квоту Google Cloud <a class="header-anchor" href="#проблема-1-не-видите-квоту-google-cloud" aria-label="Permalink to &quot;Проблема 1: Не видите квоту Google Cloud&quot;">​</a></h3><p><strong>Возможные причины</strong>:</p><ul><li>Не установлен плагин opencode-antigravity-auth</li><li>Не завершена аутентификация Google OAuth</li><li>Файл <code>antigravity-accounts.json</code> не существует или пуст</li></ul><p><strong>Решение</strong>:</p><ol><li>Установите плагин opencode-antigravity-auth</li><li>Завершите аутентификацию согласно инструкциям репозитория GitHub</li><li>Повторно выполните <code>/mystatus</code></li></ol><h3 id="проблема-2-ошибка-в-отображении-однои-учетнои-записи" tabindex="-1">Проблема 2: Ошибка в отображении одной учётной записи <a class="header-anchor" href="#проблема-2-ошибка-в-отображении-однои-учетнои-записи" aria-label="Permalink to &quot;Проблема 2: Ошибка в отображении одной учётной записи&quot;">​</a></h3><p><strong>Возможные причины</strong>:</p><ul><li>Refresh Token истёк</li><li>Отсутствует projectId</li></ul><p><strong>Пример ошибки</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@gmail.com: No project ID found</span></span></code></pre></div><p><strong>Решение</strong>:</p><ol><li>Повторно используйте плагин opencode-antigravity-auth для аутентификации этой учётной записи</li><li>Убедитесь, что при аутентификации правильно настроен ID проекта</li></ol><h3 id="проблема-3-модель-отображается-или-время-сброса-аномальное" tabindex="-1">Проблема 3: Модель отображается &quot;-&quot; или время сброса аномальное <a class="header-anchor" href="#проблема-3-модель-отображается-или-время-сброса-аномальное" aria-label="Permalink to &quot;Проблема 3: Модель отображается &quot;-&quot; или время сброса аномальное&quot;">​</a></h3><p><strong>Возможные причины</strong>:</p><ul><li>В ответе API отсутствует поле resetTime или формат аномальный</li><li>Эта модель временно не имеет информации о квоте</li></ul><p><strong>Решение</strong>:</p><ul><li>Это нормально, mystatus отобразит &quot;-&quot; для обозначения недоступности данных</li><li>Если все модели отображаются &quot;-&quot;, проверьте сетевое соединение или статус API Google Cloud</li></ul><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><ul><li>Google Cloud Antigravity поддерживает 4 модели: G3 Pro、G3 Image、G3 Flash、Claude</li><li>Каждая модель имеет независимую квоту и время сброса</li><li>Поддерживается управление несколькими учётными записями, каждая учётная запись отображается отдельно</li><li>При использовании более 80% отображается предупреждение</li></ul><h2 id="предварительныи-обзор-следующего-урока" tabindex="-1">Предварительный обзор следующего урока <a class="header-anchor" href="#предварительныи-обзор-следующего-урока" aria-label="Permalink to &quot;Предварительный обзор следующего урока&quot;">​</a></h2><blockquote><p>На следующем уроке мы изучим <strong><a href="./../../advanced/google-setup/">Расширенная настройка Google Cloud: управление несколькими учётными записями и моделями</a></strong>。</p><p>Вы узнаете:</p><ul><li>Как добавить и управлять несколькими учётными записями Google Cloud</li><li>Понять соотношение 4 моделей</li><li>Разница между projectId и managedProjectId</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите для просмотра местоположения исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Конфигурация модели</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>Логика запроса учётных записей</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>Обновление Token</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>Извлечение квоты</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>Форматирование вывода</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr><tr><td>Определение типа</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L78-L94" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>78-94</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>GOOGLE_QUOTA_API_URL = &quot;https://cloudcode-pa.googleapis.com/v1internal:fetchAvailableModels&quot;</code>：API запроса квоты Google Cloud</li><li><code>GOOGLE_TOKEN_REFRESH_URL = &quot;https://oauth2.googleapis.com/token&quot;</code>：API обновления OAuth Token</li><li><code>USER_AGENT = &quot;antigravity/1.11.9 windows/amd64&quot;</code>：User-Agent запроса API</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>queryGoogleUsage()</code>：запрос квоты всех учётных записей Antigravity</li><li><code>fetchAccountQuota()</code>：запрос квоты одной учётной записи</li><li><code>extractModelQuotas()</code>：извлечение квоты 4 моделей из ответа API</li><li><code>formatAccountQuota()</code>：форматирование отображения квоты одной учётной записи</li></ul><p><strong>Правила соответствия моделей</strong>:</p><ul><li>G3 Pro поддерживает <code>gemini-3-pro-high</code> и <code>gemini-3-pro-low</code>, приоритет основного ключа</li><li>Claude поддерживает <code>claude-opus-4-5-thinking</code> и <code>claude-opus-4-5</code>, приоритет основного ключа</li><li>G3 Image и G3 Flash только один ключ</li></ul></details>`,70)])])}const h=o(s,[["render",i]]);export{u as __pageData,h as default};
